    var route = outputChannelById(planner.output_channel_id) || (ctx && ctx.route) || null;
    var report = reportProfileById(planner.report_profile_id) || (ctx && ctx.report) || null;
    var template = workflowTemplateById(planner.workflow_template_id) || (ctx && ctx.template) || null;
    var title = caseFileTitleFromContext(ctx, planner, options.title);
