  function validationDetailText(result) {
    if (!result) return '';
    if (!result.ok) {
      return result.issues.join('\n') + (result.schemaHref ? '\nSchema: ' + result.schemaHref : '');
    }
    return result.schemaHref ? 'Schema: ' + result.schemaHref : '';
  }

