  function validateRoutingPolicyRecordFields(record, issues, path) {
    var match;
    var route;
    if (!isPlainObject(record)) {
      pushValidationIssue(issues, path, 'must be an object.');
      return;
    }
    match = record.match && typeof record.match === 'object' ? record.match : null;
    route = record.route && typeof record.route === 'object' ? record.route : null;
    validateRoutingPolicyIdField(issues, record.id, path + '.id');
    validateRequiredString(issues, record.label, path + '.label', { maxLength: 120 });
    validateRequiredString(issues, record.notes, path + '.notes', { allowEmpty: true, maxLength: 320 });
    validateDateTimeField(issues, record.created_at, path + '.created_at');
    validateDateTimeField(issues, record.updated_at, path + '.updated_at');

    if (!match) {
      pushValidationIssue(issues, path + '.match', 'must be an object.');
    } else {
      validateRoutingSeverityThresholdField(issues, match.severity_min, path + '.match.severity_min');
      validateRoutingCriticalityThresholdField(issues, match.asset_criticality_min, path + '.match.asset_criticality_min');
      validateStringArrayField(issues, match.workflow_values, path + '.match.workflow_values', {
        unique: true,
        pattern: /^(?:dependency|sast|sensitive-data|mcp-guardrail|base-image|recipe-runbook)$/,
        patternMessage: 'must reference a supported workflow value.'
      });
      validateStringArrayField(issues, match.source_ids, path + '.match.source_ids', {
        unique: true,
        pattern: /^(?:local-)?[a-z0-9]+(?:-[a-z0-9]+)*$/,
        patternMessage: 'must use a local-* or public marketplace ID.'
      });
      validateStringArrayField(issues, match.owner_teams, path + '.match.owner_teams', { unique: true });
      if (match.portfolio_ids !== undefined && match.portfolio_ids !== null) {
        validateStringArrayField(issues, match.portfolio_ids, path + '.match.portfolio_ids', {
          unique: true,
          pattern: /^portfolio-[a-z0-9]+(?:-[a-z0-9]+)*$/,
          patternMessage: 'must use a portfolio-* identifier.'
        });
      }
      validateStringArrayField(issues, match.environments, path + '.match.environments', { unique: true });
    }

    if (!route) {
      pushValidationIssue(issues, path + '.route', 'must be an object.');
    } else {
      validateMarketplaceIdField(issues, route.output_channel_id, path + '.route.output_channel_id');
      validateMarketplaceIdField(issues, route.report_profile_id, path + '.route.report_profile_id');
      validateRequiredString(issues, route.approval_gate, path + '.route.approval_gate', { maxLength: 120 });
      validateRequiredString(issues, route.context_pack, path + '.route.context_pack', { maxLength: 120 });
      validateRequiredString(issues, route.cadence, path + '.route.cadence', { maxLength: 80 });
      validateRoutingIntegrationDefaults(route.integration_defaults, issues, path + '.route.integration_defaults');
    }
  }

