  function setWorkflowLabStatus(text, kind, detail) {
    setElementStatus(els.workflowLabStatus, text, kind, detail);
  }

  function setIntegrationLabStatus(text, kind, detail) {
    setElementStatus(els.integrationLabStatus, text, kind, detail);
  }

  function workflowLabSuggestedId(value) {
    return sanitizeFilePart(value || 'workflow-pack');
  }

  function syncWorkflowLabSuggestedId(force) {
    if (!els.workflowLabLabel || !els.workflowLabId) return;
    var auto = force || els.workflowLabId.getAttribute('data-auto-id') === 'true' || !collapseText(els.workflowLabId.value);
    if (!auto) return;
    els.workflowLabId.value = workflowLabSuggestedId(els.workflowLabLabel.value);
    els.workflowLabId.setAttribute('data-auto-id', 'true');
  }

  function packGovernanceFieldSet(versionEl, ownerEl, reviewedAtEl, reviewCadenceEl, docsHrefEl) {
    return {
      version: versionEl,
      owner: ownerEl,
      reviewedAt: reviewedAtEl,
      reviewCadence: reviewCadenceEl,
      docsHref: docsHrefEl
    };
  }

  function governanceDraftFromFieldSet(fieldSet, options) {
    return normalizePackGovernance({
      pack_version: collapseText(fieldSet.version && fieldSet.version.value),
      owner: collapseText(fieldSet.owner && fieldSet.owner.value),
      reviewed_at: collapseText(fieldSet.reviewedAt && fieldSet.reviewedAt.value),
      review_cadence_days: collapseText(fieldSet.reviewCadence && fieldSet.reviewCadence.value),
      docs_href: collapseText(fieldSet.docsHref && fieldSet.docsHref.value)
    }, options || {});
  }

  function loadGovernanceFieldSet(fieldSet, governance, options) {
    var normalized = normalizePackGovernance(governance, options || {});
    if (fieldSet.version) fieldSet.version.value = normalized.pack_version || '';
    if (fieldSet.owner) fieldSet.owner.value = normalized.owner || '';
    if (fieldSet.reviewedAt) fieldSet.reviewedAt.value = normalized.reviewed_at || '';
    if (fieldSet.reviewCadence) fieldSet.reviewCadence.value = String(normalized.review_cadence_days || '');
    if (fieldSet.docsHref) fieldSet.docsHref.value = normalized.docs_href || '';
  }

  function workflowLabDraftTemplate() {
    var label = collapseText(els.workflowLabLabel && els.workflowLabLabel.value);
    var requestedId = collapseText(els.workflowLabId && els.workflowLabId.value);
    var publicId = workflowLabSuggestedId(requestedId || label);
    var payload;
    var existing;
    var collision;

    if (!label) throw new Error('Workflow pack label is required.');
    if (!publicId) throw new Error('Workflow pack ID is required.');

    payload = normalizeWorkflowTemplate({
      id: publicId,
      label: label,
      workflow_value: els.workflowLabWorkflow ? els.workflowLabWorkflow.value : AGENT_WORKFLOWS[0].value,
      description: collapseText(els.workflowLabDescription && els.workflowLabDescription.value) || 'Local browser-authored workflow pack.',
      default_recipe_query: collapseText(els.workflowLabRecipe && els.workflowLabRecipe.value) || agentWorkflowByValue(els.workflowLabWorkflow ? els.workflowLabWorkflow.value : '').prompt,
      default_context_pack: selectedText(els.workflowLabContextPack),
      default_report_profile_id: els.workflowLabReport ? els.workflowLabReport.value : '',
      default_output_channel_id: els.workflowLabOutput ? els.workflowLabOutput.value : '',
      default_input_channel_ids: els.workflowLabInputs ? selectValues(els.workflowLabInputs) : [],
      default_approval_gate: selectedText(els.workflowLabApproval),
      default_cadence: selectedText(els.workflowLabCadence),
      target_hint: collapseText(els.workflowLabTarget && els.workflowLabTarget.value),
      governance: governanceDraftFromFieldSet(
        packGovernanceFieldSet(
          els.workflowLabVersion,
          els.workflowLabOwner,
          els.workflowLabReviewedAt,
          els.workflowLabReviewCadence,
          els.workflowLabDocsHref
        ),
        {
          source: 'local',
          allowLocalRefs: true,
          owner: 'Local workflow draft',
          reviewed_at: nowIso(),
          docsHref: 'docs/control-plane-marketplace/#workflow-pack-lab'
        }
      ),
      updated_at: nowIso()
    }, { source: 'local' });

    if (!payload.default_input_channel_ids.length) {
      throw new Error('Select at least one input channel for the workflow pack.');
    }

    existing = state.workflowLabEditingId ? localWorkflowTemplateById(state.workflowLabEditingId) : null;
    collision = localWorkflowTemplateById(payload.id);
    if (collision && (!existing || collision.id !== existing.id)) {
      throw new Error('A local workflow pack already uses ID "' + publicId + '".');
    }
    if (existing && existing.created_at) payload.created_at = existing.created_at;
    return payload;
  }

  function workflowLabTemplateFromAgentConfig() {
    var template = currentWorkflowTemplate();
    var recipe = selectedRecipe();
    var publicId = template ? workflowTemplatePublicId(template) : workflowLabSuggestedId(currentAgentWorkflow().label + ' custom pack');
    var label = template
      ? (template.source === 'local' ? template.label : template.label + ' custom')
      : currentAgentWorkflow().label + ' custom pack';
    return {
      id: template && template.source === 'local' ? publicId : publicId + '-custom',
      label: label,
      workflow_value: currentAgentWorkflow().value,
      description: template && template.description
        ? template.description
        : 'Local workflow pack captured from the current browser agent planner configuration.',
      default_recipe_query: recipe ? recipeLabel(recipe) : collapseText(els.agentRecipeInput && els.agentRecipeInput.value) || currentAgentWorkflow().prompt,
      default_context_pack: selectedText(els.agentContextPack) || 'Secure context trust pack',
      default_report_profile_id: currentReportProfile() ? currentReportProfile().id : '',
      default_output_channel_id: currentAgentOutputRoute() ? currentAgentOutputRoute().id : '',
      default_input_channel_ids: currentInputChannelIds(),
      default_approval_gate: selectedText(els.agentApproval) || 'Security reviewer required',
      default_cadence: selectedText(els.agentCadence) || 'Manual approval',
      target_hint: collapseText(els.agentScope && (els.agentScope.value || els.agentScope.placeholder)) || ''
    };
  }

  function loadWorkflowLabDraft(template, options) {
    var normalized;
    options = options || {};
    if (!template || !els.workflowLabLabel) return;
    normalized = normalizeWorkflowTemplate(template, { source: options.source || (options.editingId ? 'local' : 'catalog') });
    state.workflowLabEditingId = options.editingId || '';

    els.workflowLabLabel.value = options.label || normalized.label || '';
    if (els.workflowLabId) {
      els.workflowLabId.value = options.publicId || workflowTemplatePublicId(normalized);
      els.workflowLabId.setAttribute('data-auto-id', options.autoId === false ? 'false' : 'true');
    }
    if (els.workflowLabWorkflow) els.workflowLabWorkflow.value = normalized.workflow_value;
    if (els.workflowLabRecipe) els.workflowLabRecipe.value = normalized.default_recipe_query || '';
    if (els.workflowLabDescription) els.workflowLabDescription.value = normalized.description || '';
    if (els.workflowLabReport && reportProfileById(normalized.default_report_profile_id)) {
      els.workflowLabReport.value = normalized.default_report_profile_id;
    }
    if (els.workflowLabOutput && outputChannelById(normalized.default_output_channel_id)) {
      els.workflowLabOutput.value = outputChannelById(normalized.default_output_channel_id).id;
    }
    if (els.workflowLabInputs) {
      setSelectValues(els.workflowLabInputs, normalized.default_input_channel_ids || defaultInputChannelIds());
    }
    if (els.workflowLabCadence) selectByText(els.workflowLabCadence, normalized.default_cadence || 'Manual approval');
    if (els.workflowLabApproval) selectByText(els.workflowLabApproval, normalized.default_approval_gate || 'Security reviewer required');
    if (els.workflowLabContextPack) selectByText(els.workflowLabContextPack, normalized.default_context_pack || 'Secure context trust pack');
    if (els.workflowLabTarget) els.workflowLabTarget.value = normalized.target_hint || '';
    loadGovernanceFieldSet(
      packGovernanceFieldSet(
        els.workflowLabVersion,
        els.workflowLabOwner,
        els.workflowLabReviewedAt,
        els.workflowLabReviewCadence,
        els.workflowLabDocsHref
      ),
      normalized.governance,
      {
        source: normalized.source,
        allowLocalRefs: normalized.source === 'local',
        owner: normalized.source === 'local' ? 'Local workflow draft' : 'SecurityRecipes marketplace',
        reviewed_at: normalized.updated_at || normalized.created_at || marketplaceCatalogLastReviewed(),
        docsHref: normalized.source === 'local' ? 'docs/control-plane-marketplace/#workflow-pack-lab' : ''
      }
    );

    if (!options.silent) {
      setWorkflowLabStatus(
        options.message || (state.workflowLabEditingId ? 'Editing a saved local workflow pack.' : 'Workflow pack draft loaded in the local browser lab.'),
        'ok'
      );
    }
    renderWorkflowLabTemplates();
  }

  function loadWorkflowLabFromAgentConfig(options) {
    var draft = workflowLabTemplateFromAgentConfig();
    var current = currentWorkflowTemplate();
    options = options || {};
    loadWorkflowLabDraft(draft, {
      editingId: current && current.source === 'local' ? current.id : '',
      source: current && current.source === 'local' ? 'local' : 'catalog',
      publicId: draft.id,
      autoId: current && current.source === 'local' ? false : true,
      silent: options.silent,
      message: options.message || 'Current agent planner configuration loaded into Workflow Pack Lab.'
    });
  }

  function resetWorkflowLabDraft(options) {
    options = options || {};
    state.workflowLabEditingId = '';
    if (!els.workflowLabLabel) return;
    els.workflowLabLabel.value = '';
    if (els.workflowLabId) {
      els.workflowLabId.value = '';
      els.workflowLabId.setAttribute('data-auto-id', 'true');
    }
    if (els.workflowLabWorkflow) els.workflowLabWorkflow.value = AGENT_WORKFLOWS[0].value;
    if (els.workflowLabRecipe) els.workflowLabRecipe.value = '';
    if (els.workflowLabDescription) els.workflowLabDescription.value = '';
    if (els.workflowLabReport && reportProfiles()[0]) els.workflowLabReport.value = reportProfiles()[0].id;
    if (els.workflowLabOutput && outputChannels()[0]) els.workflowLabOutput.value = outputChannels()[0].id;
    if (els.workflowLabInputs) setSelectValues(els.workflowLabInputs, defaultInputChannelIds());
    if (els.workflowLabCadence) selectByText(els.workflowLabCadence, 'Manual approval');
    if (els.workflowLabApproval) selectByText(els.workflowLabApproval, 'Security reviewer required');
    if (els.workflowLabContextPack) selectByText(els.workflowLabContextPack, 'Secure context trust pack');
    if (els.workflowLabTarget) els.workflowLabTarget.value = '';
    loadGovernanceFieldSet(
      packGovernanceFieldSet(
        els.workflowLabVersion,
        els.workflowLabOwner,
        els.workflowLabReviewedAt,
        els.workflowLabReviewCadence,
        els.workflowLabDocsHref
      ),
      null,
      {
        source: 'local',
        allowLocalRefs: true,
        owner: 'Local workflow draft',
        reviewed_at: nowIso(),
        docsHref: 'docs/control-plane-marketplace/#workflow-pack-lab'
      }
    );

    if (options.useAgentDefaults) {
      loadWorkflowLabFromAgentConfig({ silent: !!options.silent });
      return;
    }
    if (!options.silent) {
      setWorkflowLabStatus('Compose a private workflow pack locally, then copy the contribution packet into a Hugo pull request when it is ready.', '');
    }
  }

  function ensureWorkflowLabDraft() {
    if (!els.workflowLabLabel) return;
    if (collapseText(els.workflowLabLabel.value)) return;
    loadWorkflowLabFromAgentConfig({ silent: true });
  }

  function populateWorkflowLabOptions() {
    var selectedInputs;
    var selectedWorkflow;
    var selectedReport;
    var selectedOutput;
    if (!els.workflowLabWorkflow) return;

    selectedWorkflow = els.workflowLabWorkflow.value;
    els.workflowLabWorkflow.innerHTML = AGENT_WORKFLOWS.map(function (workflow) {
      return '<option value="' + html(workflow.value) + '">' + html(workflow.label) + '</option>';
    }).join('');
    els.workflowLabWorkflow.value = agentWorkflowByValue(selectedWorkflow).value;

    selectedReport = els.workflowLabReport ? els.workflowLabReport.value : '';
    if (els.workflowLabReport) {
      els.workflowLabReport.innerHTML = reportProfiles().map(function (profile) {
        return '<option value="' + html(profile.id) + '">' + html(reportProfileOptionLabel(profile)) + '</option>';
      }).join('');
      if (selectedReport && reportProfileById(selectedReport)) els.workflowLabReport.value = selectedReport;
      else if (reportProfiles()[0]) els.workflowLabReport.value = reportProfiles()[0].id;
    }

    selectedOutput = els.workflowLabOutput ? els.workflowLabOutput.value : '';
    if (els.workflowLabOutput) {
      els.workflowLabOutput.innerHTML = outputChannels().map(function (channel) {
        return '<option value="' + html(channel.id) + '">' + html(channel.label) + '</option>';
      }).join('');
      if (selectedOutput && outputChannelById(selectedOutput)) els.workflowLabOutput.value = outputChannelById(selectedOutput).id;
      else if (outputChannels()[0]) els.workflowLabOutput.value = outputChannels()[0].id;
    }

    selectedInputs = els.workflowLabInputs ? selectValues(els.workflowLabInputs) : [];
    if (els.workflowLabInputs) {
      els.workflowLabInputs.innerHTML = inputChannels().map(function (channel) {
        var meta = [channel.category, channel.runtime_support].filter(Boolean).join(' / ');
        return '<option value="' + html(channel.id) + '">' + html(channel.label + (meta ? ' - ' + meta : '')) + '</option>';
      }).join('');
      setSelectValues(els.workflowLabInputs, selectedInputs.length ? selectedInputs : defaultInputChannelIds());
    }

    syncWorkflowLabSuggestedId(false);
    renderWorkflowLabTemplates();
    ensureWorkflowLabDraft();
  }

  function renderWorkflowLabTemplates() {
    if (!els.workflowLabList) return;
    if (!state.customWorkflowTemplates || !state.customWorkflowTemplates.length) {
      els.workflowLabList.innerHTML = '<div class="ai-chatbot-workflow-lab-empty">No private workflow packs saved in this browser yet. Clone a marketplace pack or capture the current agent planner configuration.</div>';
      return;
    }
    els.workflowLabList.innerHTML = state.customWorkflowTemplates.map(function (template) {
      var route = outputChannelById(template.default_output_channel_id);
      var report = reportProfileById(template.default_report_profile_id);
      var inputs = (template.default_input_channel_ids || []).map(function (id) {
        var channel = inputChannelById(id);
        return channel ? channel.label : id;
      }).filter(Boolean);
      var runtime = workflowTemplateRuntimeSupport(template);
      var updated = template.updated_at ? 'Updated ' + formatTimestamp(template.updated_at) : 'Saved locally';
      var governance = template.governance || normalizePackGovernance(null, { source: 'local', reviewed_at: template.updated_at || template.created_at || nowIso() });
      return '<article class="ai-chatbot-workflow-lab-card">' +
        '<header>' +
          '<div>' +
            '<span class="ai-chatbot-control-plane-kind">Local pack</span>' +
            '<h3>' + html(template.label) + '</h3>' +
          '</div>' +
          '<div class="ai-chatbot-control-plane-badges">' +
            '<span>' + html(runtime) + '</span>' +
            '<span>' + html(template.workflow_value) + '</span>' +
            '<span>' + html(updated) + '</span>' +
          '</div>' +
        '</header>' +
        '<p>' + html(template.description || '') + '</p>' +
        '<dl>' +
          '<div><dt>ID</dt><dd><code>' + html(workflowTemplatePublicId(template)) + '</code></dd></div>' +
          '<div><dt>Inputs</dt><dd>' + html(inputs.join(', ') || 'none') + '</dd></div>' +
          '<div><dt>Output</dt><dd>' + html(route ? route.label : template.default_output_channel_id || 'none') + '</dd></div>' +
          '<div><dt>Report</dt><dd>' + html(report ? report.label : template.default_report_profile_id || 'none') + '</dd></div>' +
          '<div><dt>Version</dt><dd>' + html(governance.pack_version || '0.1.0-local') + '</dd></div>' +
          '<div><dt>Review</dt><dd>' + html((governance.reviewed_at || nowIso().slice(0, 10)) + ' / ' + String(governance.review_cadence_days || 30) + 'd') + '</dd></div>' +
        '</dl>' +
        '<div class="ai-chatbot-agent-actions">' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-workflow-lab-apply="' + html(template.id) + '">Apply pack</button>' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-workflow-lab-edit="' + html(template.id) + '">Edit</button>' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-workflow-lab-copy="' + html(template.id) + '">Copy JSON</button>' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-workflow-lab-copy-submission="' + html(template.id) + '">Copy submission</button>' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-workflow-lab-delete="' + html(template.id) + '">Delete</button>' +
        '</div>' +
      '</article>';
    }).join('');
  }

  function setReportLabStatus(text, kind, detail) {
    setElementStatus(els.reportLabStatus, text, kind, detail);
  }

  function reportLabSuggestedId(value) {
    return reportProfilePublicId({ label: value || 'report-profile' });
  }

  function syncReportLabSuggestedId(force) {
    if (!els.reportLabLabel || !els.reportLabId) return;
    var auto = force || els.reportLabId.getAttribute('data-auto-id') === 'true' || !collapseText(els.reportLabId.value);
    if (!auto) return;
    els.reportLabId.value = reportLabSuggestedId(els.reportLabLabel.value);
    els.reportLabId.setAttribute('data-auto-id', 'true');
  }

  function reportLabDraftProfile() {
    var label = collapseText(els.reportLabLabel && els.reportLabLabel.value);
    var requestedId = collapseText(els.reportLabId && els.reportLabId.value);
    var publicId = reportLabSuggestedId(requestedId || label);
    var payload;
    var existing;
    var collision;

    if (!label) throw new Error('Report profile label is required.');
    if (!publicId) throw new Error('Report profile ID is required.');

    payload = normalizeReportProfile({
      id: publicId,
      label: label,
      category: collapseText(els.reportLabCategory && els.reportLabCategory.value) || 'Custom reports',
      format: els.reportLabFormat ? els.reportLabFormat.value : 'json',
      description: collapseText(els.reportLabDescription && els.reportLabDescription.value) || 'Local browser-authored report profile.',
      sections: normalizeReportProfileSections(els.reportLabSections && els.reportLabSections.value),
      example_output: parseJsonObjectInput(els.reportLabExample && els.reportLabExample.value, 'Report profile example output JSON'),
      governance: governanceDraftFromFieldSet(
        packGovernanceFieldSet(
          els.reportLabVersion,
          els.reportLabOwner,
          els.reportLabReviewedAt,
          els.reportLabReviewCadence,
          els.reportLabDocsHref
        ),
        {
          source: 'local',
          allowLocalRefs: true,
          owner: 'Local report draft',
          reviewed_at: nowIso(),
          docsHref: 'docs/control-plane-marketplace/#report-profile-lab'
        }
      ),
      updated_at: nowIso()
    }, { source: 'local' });

    existing = state.reportLabEditingId ? localReportProfileById(state.reportLabEditingId) : null;
    collision = localReportProfileById(payload.id);
    if (collision && (!existing || collision.id !== existing.id)) {
      throw new Error('A local report profile already uses ID "' + publicId + '".');
    }
    if (existing && existing.created_at) payload.created_at = existing.created_at;
    return payload;
  }

  function loadReportLabDraft(profile, options) {
    var normalized;
    options = options || {};
    if (!profile || !els.reportLabLabel) return;
    normalized = normalizeReportProfile(profile, { source: options.source || (options.editingId ? 'local' : 'catalog') });
    state.reportLabEditingId = options.editingId || '';

    els.reportLabLabel.value = options.label || normalized.label || '';
    if (els.reportLabId) {
      els.reportLabId.value = options.publicId || reportProfilePublicId(normalized);
      els.reportLabId.setAttribute('data-auto-id', options.autoId === false ? 'false' : 'true');
    }
    if (els.reportLabCategory) els.reportLabCategory.value = normalized.category || '';
    if (els.reportLabFormat) els.reportLabFormat.value = normalizeReportFormat(normalized.format, 'json');
    if (els.reportLabDescription) els.reportLabDescription.value = normalized.description || '';
    if (els.reportLabSections) els.reportLabSections.value = (normalized.sections || []).join('\n');
    if (els.reportLabExample) {
      els.reportLabExample.value = JSON.stringify(normalized.example_output || {}, null, 2);
    }
    loadGovernanceFieldSet(
      packGovernanceFieldSet(
        els.reportLabVersion,
        els.reportLabOwner,
        els.reportLabReviewedAt,
        els.reportLabReviewCadence,
        els.reportLabDocsHref
      ),
      normalized.governance,
      {
        source: normalized.source,
        allowLocalRefs: normalized.source === 'local',
        owner: normalized.source === 'local' ? 'Local report draft' : 'SecurityRecipes marketplace',
        reviewed_at: normalized.updated_at || normalized.created_at || marketplaceCatalogLastReviewed(),
        docsHref: normalized.source === 'local' ? 'docs/control-plane-marketplace/#report-profile-lab' : ''
      }
    );
    if (!options.silent) {
      setReportLabStatus(
        options.message || (state.reportLabEditingId ? 'Editing a saved local report profile.' : 'Report profile draft loaded in the local browser lab.'),
        'ok'
      );
    }
    renderReportLabProfiles();
  }

  function resetReportLabDraft(options) {
    options = options || {};
    state.reportLabEditingId = '';
    if (!els.reportLabLabel) return;
    els.reportLabLabel.value = '';
    if (els.reportLabId) {
      els.reportLabId.value = '';
      els.reportLabId.setAttribute('data-auto-id', 'true');
    }
    if (els.reportLabCategory) els.reportLabCategory.value = 'Custom reports';
    if (els.reportLabFormat) els.reportLabFormat.value = 'json';
    if (els.reportLabDescription) els.reportLabDescription.value = '';
    if (els.reportLabSections) els.reportLabSections.value = 'summary';
    if (els.reportLabExample) {
      els.reportLabExample.value = JSON.stringify({ report_type: 'custom_report_profile' }, null, 2);
    }
    loadGovernanceFieldSet(
      packGovernanceFieldSet(
        els.reportLabVersion,
        els.reportLabOwner,
        els.reportLabReviewedAt,
        els.reportLabReviewCadence,
        els.reportLabDocsHref
      ),
      null,
      {
        source: 'local',
        allowLocalRefs: true,
        owner: 'Local report draft',
        reviewed_at: nowIso(),
        docsHref: 'docs/control-plane-marketplace/#report-profile-lab'
      }
    );
    if (!options.silent) {
      setReportLabStatus('Author private report profiles locally, validate them against the published schema, then reuse them in workflow packs, routing policies, and agent runs.', '');
    }
  }

  function currentReportLabContributionValidation() {
    return validateReportProfileContributionPacket(reportProfileContributionPacket(reportLabDraftProfile()));
  }

  function populateReportLabOptions() {
    if (!els.reportLabFormat) return;
    var current = els.reportLabFormat.value;
    els.reportLabFormat.innerHTML = [
      '<option value="json">json</option>',
      '<option value="markdown">markdown</option>',
      '<option value="markdown+json">markdown+json</option>'
    ].join('');
    els.reportLabFormat.value = normalizeReportFormat(current, 'json');
    syncReportLabSuggestedId(false);
    renderReportLabProfiles();
  }

  function renderReportLabProfiles() {
    if (!els.reportLabList) return;
    if (!state.customReportProfiles || !state.customReportProfiles.length) {
      els.reportLabList.innerHTML = '<div class="ai-chatbot-workflow-lab-empty">No private report profiles saved in this browser yet. Clone a marketplace report contract or author one for your downstream handoff.</div>';
      return;
    }
    els.reportLabList.innerHTML = state.customReportProfiles.map(function (profile) {
      var updated = profile.updated_at ? 'Updated ' + formatTimestamp(profile.updated_at) : 'Saved locally';
      var governance = profile.governance || normalizePackGovernance(null, { source: 'local', reviewed_at: profile.updated_at || profile.created_at || nowIso() });
      return '<article class="ai-chatbot-workflow-lab-card">' +
        '<header>' +
          '<div>' +
            '<span class="ai-chatbot-control-plane-kind">Local report</span>' +
            '<h3>' + html(profile.label) + '</h3>' +
          '</div>' +
          '<div class="ai-chatbot-control-plane-badges">' +
            '<span>' + html(profile.format || 'json') + '</span>' +
            '<span>' + html(updated) + '</span>' +
          '</div>' +
        '</header>' +
        '<p>' + html(profile.description || '') + '</p>' +
        '<dl>' +
          '<div><dt>ID</dt><dd><code>' + html(reportProfilePublicId(profile)) + '</code></dd></div>' +
          '<div><dt>Category</dt><dd>' + html(profile.category || 'Custom reports') + '</dd></div>' +
          '<div><dt>Sections</dt><dd>' + html((profile.sections || []).join(', ') || 'summary') + '</dd></div>' +
          '<div><dt>Example</dt><dd>' + html(profile.example_output && profile.example_output.report_type ? profile.example_output.report_type : 'custom report JSON') + '</dd></div>' +
          '<div><dt>Version</dt><dd>' + html(governance.pack_version || '0.1.0-local') + '</dd></div>' +
          '<div><dt>Review</dt><dd>' + html((governance.reviewed_at || nowIso().slice(0, 10)) + ' / ' + String(governance.review_cadence_days || 30) + 'd') + '</dd></div>' +
        '</dl>' +
        '<div class="ai-chatbot-agent-actions">' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-report-lab-apply="' + html(profile.id) + '">Apply to planner</button>' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-report-lab-edit="' + html(profile.id) + '">Edit</button>' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-report-lab-copy="' + html(profile.id) + '">Copy JSON</button>' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-report-lab-copy-submission="' + html(profile.id) + '">Copy submission</button>' +
          '<button class="ai-chatbot-agent-button secondary" type="button" data-report-lab-delete="' + html(profile.id) + '">Delete</button>' +
        '</div>' +
      '</article>';
    }).join('');
  }

  function integrationLabKind() {
    return els.integrationLabKind && els.integrationLabKind.value === 'output' ? 'output' : 'input';
  }

  function integrationLabLabel(kind) {
    return kind === 'output' ? 'Output channel' : 'Input channel';
  }

  function integrationLabSuggestedId(value) {
    return sanitizeFilePart(value || 'integration-pack');
  }

  function syncIntegrationLabSuggestedId(force) {
    if (!els.integrationLabLabel || !els.integrationLabId) return;
    var auto = force || els.integrationLabId.getAttribute('data-auto-id') === 'true' || !collapseText(els.integrationLabId.value);
    if (!auto) return;
    els.integrationLabId.value = integrationLabSuggestedId(els.integrationLabLabel.value);
    els.integrationLabId.setAttribute('data-auto-id', 'true');
  }

  function updateIntegrationLabUI() {
    var kind = integrationLabKind();
    if (els.integrationLabKind) els.integrationLabKind.value = kind;
    Array.prototype.forEach.call(document.querySelectorAll('[data-integration-lab-input-field]'), function (element) {
      element.hidden = kind !== 'input';
    });
    Array.prototype.forEach.call(document.querySelectorAll('[data-integration-lab-output-field]'), function (element) {
      element.hidden = kind !== 'output';
    });
    Array.prototype.forEach.call(document.querySelectorAll('[data-integration-lab-output-check]'), function (element) {
      element.hidden = kind !== 'output';
    });
    if (els.integrationLabConfig && !collapseText(els.integrationLabConfig.value)) {
      els.integrationLabConfig.value = kind === 'output'
        ? JSON.stringify({ type: 'custom_webhook' }, null, 2)
        : JSON.stringify({ type: 'custom_context' }, null, 2);
    }
  }

  function integrationLabDraftChannel() {
    var kind = integrationLabKind();
    var label = collapseText(els.integrationLabLabel && els.integrationLabLabel.value);
    var requestedId = collapseText(els.integrationLabId && els.integrationLabId.value);
    var publicId = integrationLabSuggestedId(requestedId || label);
    var category = collapseText(els.integrationLabCategory && els.integrationLabCategory.value);
    var description = collapseText(els.integrationLabDescription && els.integrationLabDescription.value);
    var runtime = normalizeRuntimeSupport(els.integrationLabRuntime && els.integrationLabRuntime.value, kind === 'output' ? 'config_only' : 'config_only');
    var config = parseJsonObjectInput(els.integrationLabConfig && els.integrationLabConfig.value, integrationLabLabel(kind) + ' config JSON');
    var payload;
    var existing;
    var collision;

    if (!label) throw new Error(integrationLabLabel(kind) + ' label is required.');
    if (!publicId) throw new Error(integrationLabLabel(kind) + ' ID is required.');

    if (kind === 'output') {
      payload = normalizeOutputChannel({
        id: publicId,
        label: label,
        category: category || 'Custom integrations',
        runtime_support: runtime,
        description: description || 'Local browser-authored output channel contract.',
        requirement: collapseText(els.integrationLabRequirement && els.integrationLabRequirement.value) || 'Review the output before sending it downstream.',
        driver: collapseText(els.integrationLabDriver && els.integrationLabDriver.value) || 'custom-output',
        browser_delivery: !!(els.integrationLabBrowserDelivery && els.integrationLabBrowserDelivery.checked),
        config: config,
        governance: governanceDraftFromFieldSet(
          packGovernanceFieldSet(
            els.integrationLabVersion,
            els.integrationLabOwner,
            els.integrationLabReviewedAt,
            els.integrationLabReviewCadence,
            els.integrationLabDocsHref
          ),
          {
            source: 'local',
            allowLocalRefs: true,
            owner: 'Local output draft',
            reviewed_at: nowIso(),
            docsHref: 'docs/control-plane-marketplace/#integration-pack-lab-and-local-library-export'
          }
        ),
        updated_at: nowIso()
      }, { source: 'local' });
      existing = state.integrationLabEditingType === 'output' && state.integrationLabEditingId ? localOutputChannelById(state.integrationLabEditingId) : null;
      collision = localOutputChannelById(payload.id);
    } else {
      payload = normalizeInputChannel({
        id: publicId,
        label: label,
        category: category || 'Custom context',
        runtime_support: runtime,
        description: description || 'Local browser-authored input channel contract.',
        auth_modes: normalizeAuthModes(els.integrationLabAuthModes && els.integrationLabAuthModes.value),
        config: config,
        governance: governanceDraftFromFieldSet(
          packGovernanceFieldSet(
            els.integrationLabVersion,
            els.integrationLabOwner,
            els.integrationLabReviewedAt,
            els.integrationLabReviewCadence,
            els.integrationLabDocsHref
          ),
          {
            source: 'local',
            allowLocalRefs: true,
            owner: 'Local input draft',
            reviewed_at: nowIso(),
            docsHref: 'docs/control-plane-marketplace/#integration-pack-lab-and-local-library-export'
          }
        ),
        updated_at: nowIso()
      }, { source: 'local' });
      existing = state.integrationLabEditingType === 'input' && state.integrationLabEditingId ? localInputChannelById(state.integrationLabEditingId) : null;
      collision = localInputChannelById(payload.id);
    }

    if (collision && (!existing || collision.id !== existing.id)) {
      throw new Error('A local ' + integrationLabLabel(kind).toLowerCase() + ' already uses ID "' + publicId + '".');
    }
    if (existing && existing.created_at) payload.created_at = existing.created_at;
    return payload;
  }

  function loadIntegrationLabDraft(channel, options) {
    var kind;
    var normalized;
    options = options || {};
    kind = options.kind === 'output' ? 'output' : 'input';
    normalized = kind === 'output'
      ? normalizeOutputChannel(channel, { source: options.source || (options.editingId ? 'local' : 'catalog') })
      : normalizeInputChannel(channel, { source: options.source || (options.editingId ? 'local' : 'catalog') });

    state.integrationLabEditingType = kind;
    state.integrationLabEditingId = options.editingId || '';
    if (els.integrationLabKind) els.integrationLabKind.value = kind;
    updateIntegrationLabUI();

    if (els.integrationLabLabel) els.integrationLabLabel.value = normalized.label || '';
    if (els.integrationLabId) {
      els.integrationLabId.value = options.publicId || (kind === 'output' ? outputChannelPublicId(normalized) : inputChannelPublicId(normalized));
      els.integrationLabId.setAttribute('data-auto-id', options.autoId === false ? 'false' : 'true');
    }
    if (els.integrationLabCategory) els.integrationLabCategory.value = normalized.category || '';
    if (els.integrationLabRuntime) els.integrationLabRuntime.value = normalizeRuntimeSupport(normalized.runtime_support, 'config_only');
    if (els.integrationLabDescription) els.integrationLabDescription.value = normalized.description || '';
    if (els.integrationLabConfig) els.integrationLabConfig.value = JSON.stringify(normalized.config || {}, null, 2);
    if (els.integrationLabAuthModes) els.integrationLabAuthModes.value = (normalized.auth_modes || []).join(', ');
    if (els.integrationLabDriver) els.integrationLabDriver.value = normalized.driver || normalized.value || '';
    if (els.integrationLabRequirement) els.integrationLabRequirement.value = normalized.requirement || '';
    if (els.integrationLabBrowserDelivery) els.integrationLabBrowserDelivery.checked = normalized.browser_delivery !== false;
    loadGovernanceFieldSet(
      packGovernanceFieldSet(
        els.integrationLabVersion,
        els.integrationLabOwner,
        els.integrationLabReviewedAt,
        els.integrationLabReviewCadence,
        els.integrationLabDocsHref
      ),
      normalized.governance,
      {
        source: normalized.source,
        allowLocalRefs: normalized.source === 'local',
        owner: kind === 'output' ? (normalized.source === 'local' ? 'Local output draft' : 'SecurityRecipes marketplace') : (normalized.source === 'local' ? 'Local input draft' : 'SecurityRecipes marketplace'),
        reviewed_at: normalized.updated_at || normalized.created_at || marketplaceCatalogLastReviewed(),
        docsHref: normalized.source === 'local' ? 'docs/control-plane-marketplace/#integration-pack-lab-and-local-library-export' : ''
      }
    );

    if (!options.silent) {
      setIntegrationLabStatus(
        options.message || (state.integrationLabEditingId ? 'Editing a saved local integration pack.' : 'Integration pack draft loaded in the local browser lab.'),
        'ok'
      );
    }
    renderIntegrationLabPacks();
  }

  function resetIntegrationLabDraft(options) {
    var kind;
    options = options || {};
    kind = options.kind === 'output' ? 'output' : integrationLabKind();
    state.integrationLabEditingType = kind;
    state.integrationLabEditingId = '';
    if (els.integrationLabKind) els.integrationLabKind.value = kind;
    if (els.integrationLabLabel) els.integrationLabLabel.value = '';
    if (els.integrationLabId) {
      els.integrationLabId.value = '';
      els.integrationLabId.setAttribute('data-auto-id', 'true');
    }
    if (els.integrationLabCategory) els.integrationLabCategory.value = kind === 'output' ? 'Custom integrations' : 'Custom context';
    if (els.integrationLabRuntime) els.integrationLabRuntime.value = 'config_only';
    if (els.integrationLabDescription) els.integrationLabDescription.value = '';
    if (els.integrationLabAuthModes) els.integrationLabAuthModes.value = 'none';
    if (els.integrationLabDriver) els.integrationLabDriver.value = 'custom-output';
    if (els.integrationLabRequirement) els.integrationLabRequirement.value = 'Review the output before sending it downstream.';
    if (els.integrationLabBrowserDelivery) els.integrationLabBrowserDelivery.checked = kind === 'output';
    if (els.integrationLabConfig) {
      els.integrationLabConfig.value = kind === 'output'
        ? JSON.stringify({ type: 'custom_webhook' }, null, 2)
        : JSON.stringify({ type: 'custom_context' }, null, 2);
    }
    loadGovernanceFieldSet(
      packGovernanceFieldSet(
        els.integrationLabVersion,
        els.integrationLabOwner,
        els.integrationLabReviewedAt,
        els.integrationLabReviewCadence,
        els.integrationLabDocsHref
      ),
      null,
      {
        source: 'local',
        allowLocalRefs: true,
        owner: kind === 'output' ? 'Local output draft' : 'Local input draft',
        reviewed_at: nowIso(),
        docsHref: 'docs/control-plane-marketplace/#integration-pack-lab-and-local-library-export'
      }
    );
    updateIntegrationLabUI();
    if (!options.silent) {
      setIntegrationLabStatus('Build private input and output packs locally, then export the contribution packet or full marketplace library when the contract set is ready.', '');
    }
  }

