    if (els.routingLabSources) setSelectValues(els.routingLabSources, []);
    if (els.routingLabOwners) els.routingLabOwners.value = '';
    if (els.routingLabPortfolios) els.routingLabPortfolios.value = '';
    if (els.routingLabEnvironments) els.routingLabEnvironments.value = '';
    if (els.routingLabOutput && outputChannels()[0]) els.routingLabOutput.value = outputChannels()[0].id;
    if (els.routingLabReport && reportProfiles()[0]) els.routingLabReport.value = reportProfiles()[0].id;
    if (els.routingLabApproval) selectByText(els.routingLabApproval, 'Security reviewer required');
    if (els.routingLabContextPack) selectByText(els.routingLabContextPack, 'Secure context trust pack');
