  function pagerDutySeverityForLevel(level) {
    if (level === 'critical') return 'critical';
    if (level === 'high') return 'error';
    if (level === 'medium') return 'warning';
    return 'info';
  }

  async function deliverPagerDuty(config, output) {
    var routingKey = getIntegrationField('pagerDutyRoutingKey');
    if (!routingKey) throw new Error('PagerDuty output needs an Events API v2 routing key saved in Agent integrations.');
    var title = firstMarkdownTitle(output, 'Security remediation event');
    var envelope = deliveryEnvelopePayload(config, output);
    var posted = await postJson('https://events.pagerduty.com/v2/enqueue', {
      body: {
        routing_key: routingKey,
        event_action: 'trigger',
        dedup_key: 'securityrecipes-' + sanitizeFilePart(title).slice(0, 48),
        payload: {
          summary: title.slice(0, 1024),
          source: window.location.hostname || 'securityrecipes.ai',
          severity: pagerDutySeverityForLevel(deliverySeverity(config, output)),
          component: collapseText(config.workflow || 'security-remediation').slice(0, 255),
          group: collapseText(config.scope || 'browser-agent').slice(0, 255),
          custom_details: envelope
        }
      }
    });
    if (!posted.response.ok) {
      throw new Error('PagerDuty Events API returned ' + statusLine(posted.response.status, posted.response.statusText) + '. Browser CORS or routing policy may require an approved relay.');
    }
    if (posted.data && posted.data.status && String(posted.data.status).toLowerCase() !== 'success') {
      throw new Error('PagerDuty rejected the event: ' + (posted.data.message || posted.data.status) + '.');
    }
    return 'PagerDuty event accepted: ' + statusLine(posted.response.status, posted.response.statusText) + '.';
  }

