  async function deliverXsoarIncident(config, output) {
    var incidentUrl = xsoarIncidentUrl();
    var apiKey = trimText(getIntegrationField('xsoarApiKey'));
    var apiKeyId = trimText(getIntegrationField('xsoarApiKeyId'));
    var posted;
    var detail = '';
    var createdId = '';
    if (!incidentUrl || !apiKey || !apiKeyId) {
      throw new Error('Cortex XSOAR output needs a base URL or incident endpoint, API key ID, and API key saved in Agent integrations.');
    }
    posted = await postJson(incidentUrl, {
      headers: {
        'Authorization': apiKey,
        'x-xdr-auth-id': apiKeyId
      },
      body: xsoarIncidentPayload(config, output)
    });
    if (posted.data) {
      detail = collapseText(
        posted.data.message ||
        posted.data.details ||
        posted.data.error ||
        posted.data.reply ||
        (posted.data.response && (posted.data.response.message || posted.data.response.details || posted.data.response.error)) ||
        ''
      );
    } else {
      detail = collapseText(posted.text || '');
    }
    if (!posted.response.ok) {
      throw new Error(
        'Cortex XSOAR returned ' + statusLine(posted.response.status, posted.response.statusText) +
        '. Browser CORS, API key scope, incident type requirements, or mandatory custom fields may require tenant-side adjustment or a copy-safe handoff.' +
        (detail ? ' ' + detail : '')
      );
    }
    createdId = collapseText(
      posted.data && (
        posted.data.id ||
        posted.data.incidentId ||
        posted.data.incident_id ||
        (posted.data.response && (posted.data.response.id || posted.data.response.incident_id || posted.data.response.incidentId))
      )
    );
    return createdId
      ? 'Cortex XSOAR incident created: ' + createdId + '.'
      : 'Cortex XSOAR incident created: ' + statusLine(posted.response.status, posted.response.statusText) + '.';
  }

  async function deliverSplunkSoarIncident(config, output) {
    var containerUrl = splunkSoarContainerUrl();
    var token = trimText(getIntegrationField('splunkSoarToken'));
    var posted;
    var detail = '';
    var containerId = '';
    if (!containerUrl || !token) {
      throw new Error('Splunk SOAR output needs a base URL or /rest/container endpoint and ph-auth-token saved in Agent integrations.');
    }
    posted = await postJson(containerUrl, {
      headers: {
        'ph-auth-token': token
      },
      body: splunkSoarContainerPayload(config, output)
    });
    if (posted.data) {
      detail = collapseText(
        posted.data.message ||
        posted.data.details ||
        posted.data.error ||
        posted.data.reason ||
        ''
      );
    } else {
      detail = collapseText(posted.text || '');
    }
    if (posted.data && posted.data.failed && posted.data.existing_container_id) {
      return 'Splunk SOAR reused existing container #' + posted.data.existing_container_id + ' for this reviewed packet.';
    }
    if (!posted.response.ok) {
      throw new Error(
        'Splunk SOAR returned ' + statusLine(posted.response.status, posted.response.statusText) +
        '. Browser CORS, ph-auth-token scope, label permissions, or tenant TLS policy may require environment-side adjustment or a copy-safe handoff.' +
        (detail ? ' ' + detail : '')
      );
    }
    if (posted.data && posted.data.failed) {
      throw new Error('Splunk SOAR rejected the container: ' + (detail || 'unknown error') + '.');
    }
    containerId = collapseText(
      posted.data && (
        posted.data.id ||
        posted.data.container_id ||
        posted.data.existing_container_id
      )
    );
    return containerId
      ? 'Splunk SOAR container created: ' + containerId + '.'
      : 'Splunk SOAR container created: ' + statusLine(posted.response.status, posted.response.statusText) + '.';
  }

