  async function deliverEmail(config, output) {
    var to = getIntegrationField('emailRecipient');
    if (!to) throw new Error('Email output needs a recipient saved in Agent integrations.');
    var subject = firstMarkdownTitle(output, 'Security remediation handoff');
    var body = agentDeliverySummary(config, output);
    var relay = getIntegrationField('smtpRelayUrl');
    if (relay) {
      var response = await fetch(relay, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ to: to, subject: subject, body: body })
      });
      if (!response.ok) throw new Error('Email relay returned ' + statusLine(response.status, response.statusText) + '. Browser CORS may require a same-origin relay.');
      return 'Email relay accepted handoff: ' + statusLine(response.status, response.statusText) + '.';
    }
    var mailto = 'mailto:' + encodeURIComponent(to) +
      '?subject=' + encodeURIComponent(subject) +
      '&body=' + encodeURIComponent(body.slice(0, 6500));
    window.location.href = mailto;
    return 'Email draft opened for ' + to + '.';
  }

  function gitLabApiBaseUrl() {
    var base = trimText(getIntegrationField('gitLabBaseUrl') || 'https://gitlab.com/api/v4').replace(/\/+$/, '');
    if (!base) return 'https://gitlab.com/api/v4';
    if (!/\/api\/v4$/i.test(base)) base += '/api/v4';
    return base;
  }

  function gitLabAuthHeaders(token) {
    var clean = trimText(token || '');
    if (!clean) return {};
    if (/^bearer\s+/i.test(clean)) return { 'Authorization': clean };
    if (/^private-token\s+/i.test(clean)) return { 'PRIVATE-TOKEN': clean.replace(/^private-token\s+/i, '') };
    return { 'PRIVATE-TOKEN': clean };
  }

  function azureDevOpsBaseUrl() {
    return trimText(getIntegrationField('azureDevOpsBaseUrl') || 'https://dev.azure.com').replace(/\/+$/, '') || 'https://dev.azure.com';
  }

  function azureDevOpsAuthorizationHeader(token) {
    var clean = trimText(token || '');
    if (!clean) return '';
    if (/^(?:basic|bearer)\s+/i.test(clean)) return clean;
    return 'Basic ' + base64EncodeText(':' + clean);
  }

  async function deliverGitLabIssue(config, output) {
    var base = gitLabApiBaseUrl();
    var project = collapseText(getIntegrationField('gitLabProject'));
    var token = trimText(getIntegrationField('gitLabToken'));
    var labels = collapseText(getIntegrationField('gitLabLabels'));
    var issueType = collapseText(getIntegrationField('gitLabIssueType') || 'issue').toLowerCase();
    var title;
    var summary;
    var response;
    var bodyText;
    var data = null;
    var detail = '';
    var params;
    if (!project || !token) {
      throw new Error('GitLab output needs a project path or ID and a token saved in Agent integrations.');
    }
    title = firstMarkdownTitle(output, 'Security remediation issue');
    summary = agentDeliverySummary(config, output);
    params = new URLSearchParams();
    params.set('title', title.slice(0, 255));
    params.set('description', summary.slice(0, 50000));
    if (labels) params.set('labels', labels);
    if (['issue', 'incident', 'task', 'test_case'].indexOf(issueType) !== -1) params.set('issue_type', issueType);
    response = await fetch(base + '/projects/' + encodeURIComponent(project) + '/issues', {
      method: 'POST',
      headers: Object.assign({
        'Accept': 'application/json',
        'Content-Type': 'application/x-www-form-urlencoded;charset=UTF-8'
      }, gitLabAuthHeaders(token)),
      body: params.toString()
    });
    bodyText = await response.text();
    if (bodyText) {
      try {
        data = JSON.parse(bodyText);
      } catch (_error) {
        data = null;
      }
    }
    if (!response.ok) {
      detail = data
        ? collapseText(typeof data.message === 'string' ? data.message : (typeof data.error === 'string' ? data.error : JSON.stringify(data.message || data.error || '')))
        : '';
      throw new Error('GitLab returned ' + statusLine(response.status, response.statusText) + '. Browser CORS, token scope, or project visibility may require a different base URL or a copy-safe handoff.' + (detail ? ' ' + detail : ''));
    }
    return 'GitLab issue created: ' + ((data && (data.web_url || (data.references && (data.references.full || data.references.relative)) || data.iid || data.id)) || 'created');
  }

  async function deliverAzureDevOpsWorkItem(config, output) {
    var base = azureDevOpsBaseUrl();
    var organization = collapseText(getIntegrationField('azureDevOpsOrganization'));
    var project = collapseText(getIntegrationField('azureDevOpsProject'));
    var workItemType = collapseText(getIntegrationField('azureDevOpsWorkItemType') || 'Issue');
    var token = trimText(getIntegrationField('azureDevOpsToken'));
    var authHeader;
    var title;
    var summary;
    var posted;
    if (!organization || !project || !token) {
      throw new Error('Azure DevOps output needs an organization, project, and token saved in Agent integrations.');
    }
    authHeader = azureDevOpsAuthorizationHeader(token);
    if (!authHeader) throw new Error('Azure DevOps token could not be normalized for the Authorization header.');
    title = firstMarkdownTitle(output, 'Security remediation work item');
    summary = agentDeliverySummary(config, output);
    posted = await postJson(
      base + '/' + encodeURIComponent(organization) + '/' + encodeURIComponent(project) +
      '/_apis/wit/workitems/$' + encodeURIComponent(workItemType) + '?api-version=7.1',
      {
        method: 'PATCH',
        headers: {
          'Accept': 'application/json',
          'Authorization': authHeader,
          'Content-Type': 'application/json-patch+json'
        },
        body: [
          { op: 'add', path: '/fields/System.Title', value: title.slice(0, 255) },
          { op: 'add', path: '/fields/System.Description', value: summary.slice(0, 30000) },
          { op: 'add', path: '/fields/System.Tags', value: 'SecurityRecipes;Security Remediation;Browser Agent' }
        ]
      }
    );
    if (!posted.response.ok) {
      throw new Error('Azure DevOps returned ' + statusLine(posted.response.status, posted.response.statusText) + '. Browser CORS, token scope, or work item type rules may require an Entra token, a PAT with Work Items write scope, or a copy-safe handoff.');
    }
    return 'Azure DevOps work item created: ' + ((posted.data && (posted.data.id || (posted.data._links && posted.data._links.html && posted.data._links.html.href) || posted.data.url)) || 'created');
  }

