  function saveScheduleDraft() {
    var now = nowIso();
    var cadence = selectedText(els.agentCadence) || 'Once at next run';
    var nextRun = els.agentNextRun && els.agentNextRun.value ? els.agentNextRun.value : '';
    if (!nextRun && cadence !== 'Manual approval') {
      nextRun = defaultAgentScheduleValue(cadence);
      if (els.agentNextRun) els.agentNextRun.value = nextRun;
    }
    if (!nextRun && cadence === 'Manual approval') {
      cadence = 'Once at next run';
      if (els.agentCadence) selectByText(els.agentCadence, cadence);
      nextRun = defaultAgentScheduleValue('Once at next run');
      if (els.agentNextRun) els.agentNextRun.value = nextRun;
    }
    if (!state.agentActions.length) state.agentActions.push(agentDraftAction());
    state.agentActions = state.agentActions.map(function (action) {
      var provider = action.provider || getAgentProvider();
      action.status = 'scheduled-draft';
      action.provider = provider;
      action.model = action.model || (els.agentModel ? collapseText(els.agentModel.value) || getModel(provider) : getModel(provider));
      action.cadence = cadence;
      action.nextRun = nextRun;
      action.updatedAt = now;
      action.scheduledAt = now;
      action.scheduledFor = nextRun;
      return action;
    });
    saveAgentActions();
    renderAgentActions();
    if (els.agentStatus) {
      els.agentStatus.textContent = 'Browser schedule saved for ' + state.agentActions.length + ' action(s), starting ' + formatTimestamp(nextRun) + '. This tab checks due actions while the site is open; closed browsers will not run them.';
      els.agentStatus.setAttribute('data-kind', 'ok');
    }
    appendTerminalRecord('system', 'scheduled ' + String(state.agentActions.length) + ' agent action(s) for ' + formatTimestamp(nextRun) + ' (' + cadence + ')');
    appendActivityRecord({
      category: 'schedule',
      eventType: 'browser_schedule_saved',
      status: 'saved',
      title: 'Saved browser agent schedule',
      summary: state.agentActions.length + ' action(s) will run only while this site stays open in the browser.',
      detail: 'The browser scheduler will check due actions locally and does not create a server-side background worker.',
      targetLabel: 'Agents',
      badges: uniqueStrings((state.agentActions || []).slice(0, 4).map(function (action) {
        return action.workflowLabel || action.workflow || 'workflow';
      }), 4)
    });
    checkBrowserAgentScheduleSoon();
  }

  function nextDueBrowserAgentActionIndex() {
    var now = Date.now();
    for (var i = 0; i < state.agentActions.length; i++) {
      var action = state.agentActions[i];
      var date = parseAgentScheduleDate(action.scheduledFor || action.nextRun);
      if (!date) continue;
      if (date.getTime() > now) continue;
      if (['generated', 'delivered', 'running', 'failed'].indexOf(action.status) !== -1) continue;
      return i;
    }
    return -1;
  }

  function checkBrowserAgentScheduleSoon() {
    window.setTimeout(checkBrowserAgentSchedule, 0);
  }

  async function checkBrowserAgentSchedule() {
    if (state.agentRunning || state.agentScheduleRunning || document.hidden) return;
    var index = nextDueBrowserAgentActionIndex();
    if (index < 0) return;
    state.agentScheduleRunning = true;
    try {
      var config = agentConfigForAction(state.agentActions[index]);
      var sessionContext = createActivitySession('agent_run', agentRunSessionLabel(config, true));
      await prepareAgentRunContext({ activityContext: sessionContext });
      await runAgentPreview(config, { actionIndex: index, scheduled: true, activityContext: sessionContext });
    } finally {
      state.agentScheduleRunning = false;
    }
  }

  function startBrowserAgentScheduler() {
    if (state.agentScheduleTimer) window.clearInterval(state.agentScheduleTimer);
    state.agentScheduleTimer = window.setInterval(function () {
      renderAgentActions();
      checkBrowserAgentSchedule();
    }, AGENT_SCHEDULER_INTERVAL_MS);
    document.addEventListener('visibilitychange', function () {
      if (!document.hidden) checkBrowserAgentScheduleSoon();
    });
    window.addEventListener('focus', checkBrowserAgentScheduleSoon);
    checkBrowserAgentScheduleSoon();
  }

  function agentRunSessionLabel(config, scheduled) {
    var workflowLabel = collapseText(config && (config.workflowLabel || config.workflow)) || 'Agent run';
    var scope = collapseText(config && config.scope) || 'current target';
    return workflowLabel + ' / ' + scope + (scheduled ? ' / scheduled' : '');
  }

  function chatSessionLabel(text) {
    var prompt = collapseText(text || '').slice(0, 72);
    return prompt ? ('Chat investigation / ' + prompt) : 'Chat investigation';
  }

  async function prepareAgentRunContext(options) {
    options = options || {};
    return withActivityContext(options.activityContext, async function () {
      await ensureDocsIndex();
      if (state.includeGitHub) await prepareGitHubContext();
      if (state.includeGitHubCodeScanning) await prepareGitHubCodeScanningContext();
      if (state.includeGitLabProject) await prepareGitLabProjectContext();
      if (state.includeGitLabFindings) await prepareGitLabFindingContext();
      if (state.includeAzureDevOpsRepository) await prepareAzureDevOpsRepositoryContext();
      if (state.includeDefenderXdr) await prepareDefenderXdrContext();
      if (state.includeSentinel) await prepareSentinelContext();
      if (state.includeDepsDev) await prepareDepsDevContext();
      if (state.includeSnyk) await prepareSnykContext();
      if (state.includeConfluence) await prepareConfluenceContext((els.agentScope && els.agentScope.value) || (els.agentRecipeInput && els.agentRecipeInput.value) || '');
      if (!state.agentRecipePath && els.agentRecipeInput && collapseText(els.agentRecipeInput.value)) {
        var inferredRecipe = selectedRecipe();
        if (inferredRecipe) selectAgentRecipe(inferredRecipe);
      }
    });
  }

  async function runAgentPreview(config, options) {
    options = options || {};
    if (state.agentRunning) return;
    var actionIndex = typeof options.actionIndex === 'number' ? options.actionIndex : -1;
    var sessionContext = normalizeActivityContext(options.activityContext) || createActivitySession('agent_run', agentRunSessionLabel(config, options.scheduled));
    rememberActivitySession(sessionContext);
    return withActivityContext(sessionContext, async function () {
      var startedAt = Date.now();
      state.agentRunning = true;
      if (actionIndex >= 0 && state.agentActions[actionIndex]) {
        state.agentActions[actionIndex].status = 'running';
        state.agentActions[actionIndex].lastBrowserCheckAt = nowIso();
        state.agentActions[actionIndex].updatedAt = nowIso();
        saveAgentActions();
        renderAgentActions();
      }
      if (els.agentPreview) els.agentPreview.disabled = true;
      if (els.agentStatus) {
        els.agentStatus.textContent = 'Running ' + config.workflow + ' with ' + providerConfig(config.provider).label + (options.scheduled ? ' from browser schedule' : '') + '...';
        els.agentStatus.removeAttribute('data-kind');
      }
      appendTerminalRecord('system', 'agent preview started: ' + config.workflow + ' / ' + config.scope);
      appendActivityRecord({
        category: 'agent',
        eventType: options.scheduled ? 'scheduled_agent_started' : 'agent_preview_started',
        status: 'running',
        title: 'Started agent preview',
        summary: (config.workflowLabel || config.workflow) + ' started for ' + (config.scope || 'the current target') + '.',
        detail: providerConfig(config.provider).label + ' / ' + config.model + (options.scheduled ? ' from the browser scheduler.' : ' from a manual browser run.'),
        targetLabel: config.scope || 'agent planner',
        badges: [providerConfig(config.provider).label, config.model, config.workflowLabel || config.workflow]
      });

      try {
        var prompt = agentPrompt(config);
        var system = buildSystemPrompt(prompt) +
          '\n\nYou are running as a browser-scheduled remediation agent preview. Do not claim to have created tickets, commits, pull requests, or background jobs.';
        var answer = await sendToProvider(prompt, {
          provider: config.provider,
          model: config.model,
          history: [],
          system: system
        });
        state.agentLastOutput = answer;
        state.agentLastConfig = config;
        state.caseboardLastSavedId = '';
        await executeAgentTerminalCommands(answer);
        var finishedAt = nowIso();
        if (actionIndex >= 0 && state.agentActions[actionIndex]) {
          var completedAction = state.agentActions[actionIndex];
          var nextRecurringRun = nextRecurringAgentRunValue(completedAction, finishedAt);
          completedAction.lastBrowserRunAt = finishedAt;
          completedAction.updatedAt = finishedAt;
          if (nextRecurringRun) {
            completedAction.status = 'scheduled-draft';
            completedAction.lastRunStatus = 'generated';
            completedAction.nextRun = nextRecurringRun;
            completedAction.scheduledFor = nextRecurringRun;
            appendTerminalRecord('system', 'agent rescheduled: ' + agentActionTitle(completedAction) + ' -> ' + formatTimestamp(nextRecurringRun));
          } else {
            completedAction.status = 'generated';
          }
        } else {
          state.agentActions = (config.actions || state.agentActions).map(function (action) {
            action.status = 'generated';
            action.updatedAt = finishedAt;
            action.lastBrowserRunAt = finishedAt;
            return action;
          });
        }
        saveAgentActions();
        renderAgentActions();
        renderAgentOutput(answer, false);
        updateAgentMarketplacePreview();
        if (els.agentStatus) {
          els.agentStatus.textContent = 'Preview completed with ' + providerConfig(config.provider).label + ' / ' + config.model + '.';
          els.agentStatus.setAttribute('data-kind', 'ok');
        }
        appendTerminalRecord('system', 'agent preview completed: ' + providerConfig(config.provider).label + ' / ' + config.model);
        appendActivityRecord({
          category: 'agent',
          eventType: options.scheduled ? 'scheduled_agent_completed' : 'agent_preview_completed',
          status: 'ok',
          title: 'Completed agent preview',
          summary: (config.workflowLabel || config.workflow) + ' produced a reviewed plan for ' + (config.scope || 'the current target') + '.',
          detail: providerConfig(config.provider).label + ' / ' + config.model + ' completed the browser-local plan generation path.',
          targetLabel: config.scope || 'agent planner',
          durationMs: Date.now() - startedAt,
          badges: [providerConfig(config.provider).label, config.model, config.outputRoute || 'preview']
        });
      } catch (error) {
        if (actionIndex >= 0 && state.agentActions[actionIndex]) {
          state.agentActions[actionIndex].status = 'failed';
          state.agentActions[actionIndex].updatedAt = nowIso();
          saveAgentActions();
          renderAgentActions();
        }
        renderAgentOutput(failureMessage(error), true);
        if (els.agentStatus) {
          els.agentStatus.textContent = 'Agent preview failed.';
          els.agentStatus.setAttribute('data-kind', 'error');
        }
        appendTerminalRecord('error', error && error.message ? error.message : 'Agent preview failed.');
        appendActivityRecord({
          category: 'agent',
          eventType: options.scheduled ? 'scheduled_agent_failed' : 'agent_preview_failed',
          status: 'error',
          title: 'Agent preview failed',
          summary: error && error.message ? error.message : 'Agent preview failed.',
          detail: 'The reviewed browser-local plan did not complete successfully.',
          targetLabel: config.scope || 'agent planner',
          durationMs: Date.now() - startedAt,
          badges: [providerConfig(config.provider).label, config.model, config.workflowLabel || config.workflow]
        });
      } finally {
        state.agentRunning = false;
        if (els.agentPreview) els.agentPreview.disabled = false;
      }
    });
  }

  async function handleAgentPreview() {
    if (state.agentRunning) return;
    var config = agentConfig();
    var sessionContext = createActivitySession('agent_run', agentRunSessionLabel(config, false));
    await prepareAgentRunContext({ activityContext: sessionContext });
    await runAgentPreview(config, { activityContext: sessionContext });
  }

  async function runAgentActionNow(index) {
    if (state.agentRunning) return;
    var action = state.agentActions && state.agentActions[index];
    if (!action) return;
    var config = agentConfigForAction(action);
    var sessionContext = createActivitySession('agent_run', agentRunSessionLabel(config, true));
    await prepareAgentRunContext({ activityContext: sessionContext });
    await runAgentPreview(config, { actionIndex: index, scheduled: action.status === 'scheduled-draft', activityContext: sessionContext });
  }

  async function handleContextCheckQuickAction() {
    if (state.sending) return;
    var rows = contextAuditRows();
    var localSummary = contextAuditMarkdown(rows, 'Context check summary');
    var prompt = 'Summarize the following browser-local SecurityRecipes chat context into a concise bullet list for a vulnerability remediation operator. Separate ready context, missing or stale context, and recommended next action.\n\n' + localSummary;
    var userMessage = {
      role: 'user',
      content: 'Context check',
      createdAt: nowIso()
    };
    var assistantMessage = {
      role: 'assistant',
      content: getToken(getAgentProvider()) ? '' : localSummary,
      createdAt: nowIso(),
      provider: getAgentProvider(),
      streaming: !!getToken(getAgentProvider())
    };
    state.messages.push(userMessage, assistantMessage);
    saveChatHistoryStorage();
    renderMessages();
    appendTerminalRecord('system', 'context check requested');
    if (!getToken(getAgentProvider())) {
      setStatus('Context check generated locally. Save a provider credential for LLM summarization.', 'ok');
      appendActivityRecord({
        category: 'chat',
        eventType: 'context_check_local',
        status: 'ok',
        title: 'Generated local context check',
        summary: 'Context sources, marketplace inputs, terminal transcript, and gaps were summarized without calling an LLM.',
        targetLabel: 'Chat context',
        badges: ['local summary', String(rows.selectedInputs.length) + ' inputs']
      });
      return;
    }
    state.sending = true;
    if (els.send) els.send.disabled = true;
    setStatus('Summarizing current context with ' + providerConfig(getAgentProvider()).label + '...', '');
    try {
      var answer = await sendToProvider(prompt, {
        provider: getAgentProvider(),
        model: getModel(getAgentProvider()),
        history: [],
        system: 'You summarize remediation context. Use short bullets. Do not invent loaded sources or credentials.'
      });
      assistantMessage.streaming = false;
      assistantMessage.content = answer || localSummary;
      saveChatHistoryStorage();
      setStatus('Context check completed', 'ok');
      appendActivityRecord({
        category: 'chat',
        eventType: 'context_check_completed',
        status: 'ok',
        title: 'Completed context check',
        summary: 'LLM summarized the current chat context, selected inputs, evidence, and route readiness.',
        targetLabel: providerConfig(getAgentProvider()).label,
        badges: [providerConfig(getAgentProvider()).label, getModel(getAgentProvider())]
      });
    } catch (error) {
      assistantMessage.streaming = false;
      assistantMessage.error = true;
      assistantMessage.content = localSummary + '\n\nLLM summary failed: ' + (error && error.message ? error.message : 'Provider request failed.');
      saveChatHistoryStorage();
      setStatus('Context check fell back to local summary', 'error');
    } finally {
      state.sending = false;
      if (els.send) els.send.disabled = false;
      renderMessages();
    }
  }

  async function handleSend(event) {
    event.preventDefault();
    if (state.sending) return;
    var text = collapseText(els.prompt.value);
    if (!text) return;
    var assistantMessage = null;
    var requestStartedAt = Date.now();

    state.messages.push({ role: 'user', content: text, createdAt: nowIso() });
    saveChatHistoryStorage();
    els.prompt.value = '';
    renderMessages();

    var terminalCommand = commandFromChatText(text);
    if (terminalCommand) {
      setStatus('Running browser terminal command...', '');
      state.sending = true;
      els.send.disabled = true;
      try {
        var terminalOutput = await executeTerminalCommand(terminalCommand, { source: 'chat' });
        state.messages.push({
          role: 'assistant',
          content: 'Terminal result:\n\n```text\n' + terminalOutput + '\n```',
          createdAt: nowIso()
        });
        saveChatHistoryStorage();
        setStatus('Terminal command completed', 'ok');
      } catch (error) {
        state.messages.push({
          role: 'assistant',
          content: failureMessage(error),
          error: true,
          createdAt: nowIso()
        });
        saveChatHistoryStorage();
        setStatus('Terminal command failed', 'error');
      } finally {
        state.sending = false;
        els.send.disabled = false;
        renderMessages();
      }
      return;
    }

    setStatus('Building site context...', '');
    state.sending = true;
    els.send.disabled = true;
    var chatSession = createActivitySession('chat_session', chatSessionLabel(text));
    rememberActivitySession(chatSession);

    try {
      await withActivityContext(chatSession, async function () {
        try {
          await ensureDocsIndex();
          if (state.includeGitHub) await prepareGitHubContext();
          if (state.includeGitHubCodeScanning) await prepareGitHubCodeScanningContext();
          if (state.includeGitLabProject) await prepareGitLabProjectContext();
          if (state.includeGitLabFindings) await prepareGitLabFindingContext();
          if (state.includeAzureDevOpsRepository) await prepareAzureDevOpsRepositoryContext();
          if (state.includeDefenderXdr) await prepareDefenderXdrContext();
          if (state.includeSentinel) await prepareSentinelContext();
          if (state.includeDepsDev) await prepareDepsDevContext();
          if (state.includeSnyk) await prepareSnykContext();
          if (state.includeConfluence) await prepareConfluenceContext(text);
          var history = apiHistory();
          var system = buildSystemPrompt(text);
          assistantMessage = { role: 'assistant', content: '', createdAt: nowIso(), streaming: true, provider: state.provider };
          state.messages.push(assistantMessage);
          renderMessages();
          setStatus('Streaming from ' + providerConfig().label + '...', '');
          var answer = await sendToProvider(text, {
            history: history,
            system: system,
            onDelta: function (delta) {
              assistantMessage.content += delta;
              renderMessages();
            }
          });
          assistantMessage.streaming = false;
          if (!assistantMessage.content.trim()) assistantMessage.content = answer;
          saveChatHistoryStorage();
          setStatus(maskToken(getToken()), 'ok');
          appendActivityRecord({
            category: 'chat',
            eventType: 'chat_completed',
            status: 'ok',
            title: 'Completed chat investigation',
            summary: 'Ad-hoc browser chat returned from ' + providerConfig().label + ' / ' + getModel() + '.',
            detail: 'Selected inputs: ' + currentInputChannelIds().map(function (id) {
              var channel = inputChannelById(id);
              return channel ? channel.label : id;
            }).join(', '),
            targetLabel: providerConfig().label,
            durationMs: Date.now() - requestStartedAt,
            badges: [providerConfig().label, getModel(), String(currentInputChannelIds().length) + ' inputs']
          });
        } catch (error) {
          if (!getToken()) setSettingsOpen(true);
          if (assistantMessage) {
            assistantMessage.streaming = false;
            assistantMessage.error = true;
            assistantMessage.content = assistantMessage.content.trim()
              ? assistantMessage.content + '\n\n' + failureMessage(error)
              : failureMessage(error);
          } else {
            state.messages.push({
              role: 'assistant',
              content: failureMessage(error),
              error: true,
              createdAt: nowIso()
            });
          }
          saveChatHistoryStorage();
          setStatus('Request failed', 'error');
          appendActivityRecord({
            category: 'chat',
            eventType: 'chat_failed',
            status: 'error',
            title: 'Chat investigation failed',
            summary: error && error.message ? error.message : 'Provider request failed.',
            detail: 'The browser-side chat request did not complete successfully.',
            targetLabel: providerConfig().label,
            durationMs: Date.now() - requestStartedAt,
            badges: [providerConfig().label, getModel()]
          });
        }
      });
    } finally {
      state.sending = false;
      els.send.disabled = false;
      renderMessages();
    }
  }

