    els.launch.addEventListener('click', function () {
      var isOpen = !els.panel.hidden;
      els.panel.hidden = isOpen;
      els.launch.setAttribute('aria-expanded', isOpen ? 'false' : 'true');
      if (isOpen) {
        setExpanded(false);
        return;
      }
      openPanel('chat');
    });

    els.expand.addEventListener('click', function () {
      if (els.panel.hidden) openPanel('chat');
      setExpanded(els.panel.getAttribute('data-expanded') !== 'true');
    });

    if (els.settingsButton) {
      els.settingsButton.addEventListener('click', function () {
        if (els.panel.hidden) openPanel('chat');
        var activePanel = els.panel.getAttribute('data-active-panel') || 'chat';
        setSettingsOpen(activePanel !== 'settings');
        if (state.settingsOpen) {
          window.setTimeout(function () {
            var target = els.settingsContent && els.settingsContent.querySelector('input, select, button, summary');
            if (target) target.focus();
          }, 0);
        }
      });
    }

    els.providerBadge.addEventListener('click', refreshProviderConnectivity);

    shell.querySelector('[data-close]').addEventListener('click', function () {
      setExpanded(false);
      els.panel.hidden = true;
      els.launch.setAttribute('aria-expanded', 'false');
      els.launch.focus();
    });

    shell.addEventListener('keydown', function (event) {
      // Keep site-wide search shortcuts from handling keystrokes typed inside the AI workbench.
      event.stopPropagation();
    });
    shell.addEventListener('mousedown', function (event) {
      // Hextra's document-level search listener assumes a visible site search box.
      event.stopPropagation();
    });
    document.addEventListener('keydown', function (event) {
      if (event.target && event.target.closest && event.target.closest('.ai-chatbot-shell')) {
        event.stopImmediatePropagation();
      }
    }, true);

    Array.prototype.forEach.call(shell.querySelectorAll('.ai-chatbot-tab'), function (button) {
      button.addEventListener('click', function () {
        var tabName = button.getAttribute('data-tab');
        var panelName = panelForTab(tabName);
        switchTab(tabName);
        if (panelName === 'search' && els.searchInput) {
          window.setTimeout(function () { els.searchInput.focus(); }, 0);
        } else if (panelName === 'router' && els.routerRecommendations) {
          window.setTimeout(function () {
            var routerButton = els.routerRecommendations.querySelector('button');
            if (routerButton) routerButton.focus();
          }, 0);
        } else if (panelName === 'control-plane' && els.controlPlaneSearch) {
          window.setTimeout(function () { els.controlPlaneSearch.focus(); }, 0);
        } else if (panelName === 'terminal') {
          window.setTimeout(function () {
            var terminalInput = (els.terminalInputs && els.terminalInputs[0]) || els.terminalInput;
            if (terminalInput) terminalInput.focus();
          }, 0);
        } else if (panelName === 'assets' && els.assetSearch) {
          window.setTimeout(function () { els.assetSearch.focus(); }, 0);
        } else if (panelName === 'exposure' && els.exposureSearch) {
          window.setTimeout(function () { els.exposureSearch.focus(); }, 0);
        } else if (panelName === 'cases' && els.caseboardSearch) {
          window.setTimeout(function () { els.caseboardSearch.focus(); }, 0);
        } else if (panelName === 'reports' && els.reportSourceId) {
          window.setTimeout(function () { els.reportSourceId.focus(); }, 0);
        }
      });
    });

    shell.addEventListener('click', function (event) {
      var button = event.target.closest('[data-open-panel]');
      if (!button || !shell.contains(button)) return;
      var target = button.getAttribute('data-open-panel') || 'agents';
      if (button.getAttribute('data-focus-terminal') === 'true') {
        focusTerminalWorkbench();
        return;
      }
      switchTab(target);
      window.setTimeout(function () {
        if (target === 'control-plane' && els.controlPlaneSearch) els.controlPlaneSearch.focus();
        else if (target === 'router' && els.routerRecommendations) {
          var routerButton = els.routerRecommendations.querySelector('button');
          if (routerButton) routerButton.focus();
        } else if (target === 'assets' && els.assetSearch) els.assetSearch.focus();
        else if (target === 'exposure' && els.exposureSearch) els.exposureSearch.focus();
        else if (target === 'cases' && els.caseboardSearch) els.caseboardSearch.focus();
        else if (target === 'reports' && els.reportSourceId) els.reportSourceId.focus();
        else if (els.agentRecipeInput) els.agentRecipeInput.focus();
      }, 0);
    });

    var workbenchMenuToggle = shell.querySelector('[data-workbench-menu-toggle]');
    if (workbenchMenuToggle) {
      function syncWorkbenchMenuHeight(open) {
        var menu = workbenchMenuToggle.closest('[data-workbench-menu]');
        var content = menu && menu.querySelector('[data-workbench-menu-content]');
        if (!menu) return;
        var height = workbenchMenuToggle.offsetHeight + 2;
        if (open && content) height += content.scrollHeight;
        menu.style.minHeight = Math.max(58, height) + 'px';
      }
      workbenchMenuToggle.addEventListener('click', function () {
        var menu = workbenchMenuToggle.closest('[data-workbench-menu]');
        var content = menu && menu.querySelector('[data-workbench-menu-content]');
        var open = workbenchMenuToggle.getAttribute('aria-expanded') === 'true';
        workbenchMenuToggle.setAttribute('aria-expanded', open ? 'false' : 'true');
        if (menu) menu.setAttribute('data-open', open ? 'false' : 'true');
        if (content) content.hidden = open;
        syncWorkbenchMenuHeight(!open);
      });
      window.addEventListener('resize', function () {
        syncWorkbenchMenuHeight(workbenchMenuToggle.getAttribute('aria-expanded') === 'true');
      });
      syncWorkbenchMenuHeight(false);
    }

    if (els.chatQuickActions) {
      els.chatQuickActions.addEventListener('click', function (event) {
        var button = event.target.closest('[data-chat-quick]');
        var action = button && button.getAttribute('data-chat-quick');
        var text = '';
        if (!action) return;
        if (action === 'context') {
          handleContextCheckQuickAction();
          return;
        }
        text = 'Run the best matching SecurityRecipes remediation recipe using the current page context, selected marketplace inputs, uploaded evidence, and reviewer-gated output route. Produce commands, checks, rollback, and the handoff packet.';
        if (els.prompt) {
          els.prompt.value = text;
          els.prompt.focus();
        }
        if (els.form && typeof els.form.requestSubmit === 'function') els.form.requestSubmit();
        else if (els.form) els.form.dispatchEvent(new Event('submit', { bubbles: true, cancelable: true }));
      });
    }

    if (els.searchInput) {
      els.searchInput.addEventListener('input', runSearch);
      els.searchInput.addEventListener('focus', runSearch);
    }
